    this._cutPreferences = {};
    this._currentNotes = "";
    this._showNotes = false;
    this._showActiveTempAdjust = false;
    this._activeTempAdjustC = null;
    this._showNinjaCombi = false;
    this._selectedNinjaRecipe = null;
    this._showRecipeBuilder = false;
